import{u as e}from"./index.95f2040e.js";import{_ as n,c as a,o as i,f as t}from"./entry.79f37cee.js";import"./vue.f36acd1f.494dcfe6.js";const s={class:"row"},r=t('<div class="col-xs-12 col-md-offset-1 col-lg-offset-2 col-lg-9 col-md-10" data-v-2cc85ca5><h2 class="z-100" data-v-2cc85ca5> Mein Angebot </h2><h1 class="z-100" data-v-2cc85ca5> Agile Organisationsberatung </h1><h3 class="z-100" data-v-2cc85ca5>Nachhaltige Veränderungsprozesse gestalten und zukunftsfähige Organisationen entwickeln</h3><p class="z-100" data-v-2cc85ca5>In einer Welt im Wandel sind Organisationen, die schnell auf Veränderungen reagieren können, wichtiger denn je. Die zunehmende Komplexität und Geschwindigkeit stellt Unternehmen und ihre Mitarbeitende vor neue Herausforderungen.</p><p class="z-100" data-v-2cc85ca5>Als Organisationsberaterin unterstütze ich insbesondere kleine und mittlere Unternehmen dabei, diesen Herausforderungen wirksam zu begegnen und sich weiterzuentwickeln.</p><h2 class="z-100" data-v-2cc85ca5>Mein Ansatz</h2><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Partizipativ: </b>Ich glaube daran, dass Veränderungen am nachhaltigsten sind, wenn sie gemeinschaftlich gestaltet werden. Daher arbeite ich eng mit allen Stakeholdern zusammen, um die unterschiedlichen Perspektiven und Erfahrungen einzubeziehen.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Iterativ: </b>Veränderungen werden schrittweise und kontinuierlich umgesetzt, Feedback wird in den Entwicklungsprozess integriert. Dieser Ansatz der Organisationsentwicklung ermöglicht eine organische Entwicklung und bedarf keines umfangreichen Transformationsprojekts.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Individuell: </b>Ich verkaufe keine Frameworks oder bestimmte Methoden. Gemeinsam mit euch erarbeite ich individuelle Lösungen, die perfekt zu euren Herausforderungen und Zielen passen. Dabei bringe ich meine jahrelange Erfahrung in der Arbeit in und mit agilen Teams und Unternehmen ein.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Wirkungsvoll: </b>Mein Ziel ist es, die Fähigkeit zur kontinuierlichen Weiterentwicklung innerhalb der Organisation zu stärken und flexibel auf Veränderungen reagieren zu können.</p><h2 class="z-100" data-v-2cc85ca5>Meine Leistungen</h2><h3 class="z-100" data-v-2cc85ca5>Die Organisation weiterentwickeln</h3><p class="z-100" data-v-2cc85ca5>Euer Unternehmen befindet sich in einer starken Wachstums- oder Umbruchphase? Prozesse und Strukturen stoßen an ihre Grenzen? Ihr wollt dabei auf Teamarbeit und Selbstorganisation setzen?</p><p class="z-100" data-v-2cc85ca5>Das erreichen wir gemeinsam:</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Mehr Klarheit: </b>Wir durchleuchten eure Entscheidungs- und Kommunikationswege und schärfen Rollen und Verantwortlichkeiten.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Notwendige Strukturen: </b>Ich unterstütze euch dabei, die richtigen Rahmenbedingungen für Selbstorganisation und Teamarbeit zu schaffen.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Neue Lösungsansätze: </b>Mit meinem frischen Blick von außen und neuen, innovativen Perspektiven auf eure Organisation finden wir gemeinsam neue Lösungsansätze.</p><h3 class="z-100" data-v-2cc85ca5> Digitale Transformationsprozesse</h3><p class="z-100" data-v-2cc85ca5>Steht die Digitalisierung eines oder mehrerer Prozesse bei euch an? Ob ihr euer Wissensmanagement, eure Kommunikation oder das Kundenerlebnis neu und digital gestalten wollt, ich begleite euch bei der Gestaltung und Umsetzung digitaler Transformationsprozesse. Gemeinsam finden wir nachhaltige Lösungen.</p><p class="z-100" data-v-2cc85ca5>Das erreichen wir gemeinsam:</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Höhere Akzeptanz: </b>Wir beziehen die relevanten Stakeholder ein und erreichen so eine hohe Akzeptanz der Veränderung.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Nachhaltigere Ergebnisse: </b>Die höhere Akzeptanz führt zu nachhaltigeren Ergebnissen und einer motivierteren Nutzung von neuen Prozessen und Strukturen.</p><p class="z-100" data-v-2cc85ca5><b data-v-2cc85ca5>Das beste Ergebnis: </b>Die Mitarbeitenden kennen die Prozesse und Herausforderungen am besten.</p></div>',1),c=[r],d={name:"agile-Organisationsberatung"},u=Object.assign(d,{setup(l){return e({title:"Agile Organisationsberatung",ogTitle:"Agile Organisationsberatung",ogDescription:"Als Organisationsberaterin unterstütze ich Unternehmen dabei, Veränderungsprozesse zu gestalten. Dabei arbeite ich gerne mit agilen Methoden. Mein Ziel ist es, langfristig die Fähigkeit zur kontinuierlichen Weiterentwicklung innerhalb der Organisation zu stärken.",description:"Als Organisationsberaterin unterstütze ich Unternehmen dabei, Veränderungsprozesse zu gestalten. Dabei arbeite ich gerne mit agilen Methoden. Mein Ziel ist es, langfristig die Fähigkeit zur kontinuierlichen Weiterentwicklung innerhalb der Organisation zu stärken."}),(g,o)=>(i(),a("div",s,c))}}),m=n(u,[["__scopeId","data-v-2cc85ca5"]]);export{m as default};
